update server_resources_renewal
set resources_id = #{newResourcesId}
where user_id = #{userId}
and resources_id = #{oldResourcesId}

mapper.select:
select
id, resources_id, renewal_switch, user_id, renewal_period, renewal_time, renewal_promo, is_agree_original_price,
acceptable_price_increase_pct, current_price_snapshot, is_deleted, create_user, update_user, create_time,
update_time, status
from server_resources_renewal

    1 = 1 and is_deleted = 0

        and id = #{id}


        and resources_id = #{resourcesId}


        and renewal_switch = #{renewalSwitch}


        and user_id = #{userId}


        and renewal_period = #{renewalPeriod}


        and renewal_time = #{renewalTime}


        and renewal_promo = #{renewalPromo}


        and is_agree_original_price = #{isAgreeOriginalPrice}


        and acceptable_price_increase_pct = #{acceptablePriceIncreasePct}


        and current_price_snapshot = #{currentPriceSnapshot}


        and is_deleted = #{isDeleted}


        and create_user = #{createUser}


        and update_user = #{updateUser}


        and create_time = #{createTime}


        and update_time = #{updateTime}


        and status = #{status}

